import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.ParserConfigurationException;
import org.xml.sax.SAXException;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import java.io.ByteArrayInputStream;
import java.io.InputStream;

@Configuration
public class SecureXmlConfiguration {

    @Bean
    public DocumentBuilderFactory secureDocumentBuilderFactory() throws ParserConfigurationException {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();

        // Disable DTDs (Document Type Definitions) completely
        factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);

        // Disable external entities
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);

        // Disable external DTDs
        factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);

        // Enable secure processing
        factory.setFeature(javax.xml.XMLConstants.FEATURE_SECURE_PROCESSING, true);

        // Set entity expansion limits (JDK 7u45+, 8+)
        factory.setAttribute("http://www.oracle.com/xml/jaxp/properties/entityExpansionLimit", "0");
        factory.setAttribute("http://www.oracle.com/xml/jaxp/properties/elementAttributeLimit", "10000");
        factory.setAttribute("http://www.oracle.com/xml/jaxp/properties/maxOccurLimit", "5000");
        factory.setAttribute("http://www.oracle.com/xml/jaxp/properties/totalEntitySizeLimit", "50000000"); // 50MB

        // Disable XInclude processing
        factory.setXIncludeAware(false);
        factory.setExpandEntityReferences(false);

        return factory;
    }

    /**
     * Secure XML parsing method for REST controllers
     */
    public org.w3c.dom.Document parseXmlSecurely(String xmlContent) throws Exception {
        DocumentBuilder builder = secureDocumentBuilderFactory().newDocumentBuilder();

        // Set custom EntityResolver to prevent external entity resolution
        builder.setEntityResolver((publicId, systemId) -> {
            throw new SAXException("External entities are not allowed");
        });

        InputStream is = new ByteArrayInputStream(xmlContent.getBytes("UTF-8"));
        return builder.parse(is);
    }
}

