import org.springframework.web.bind.annotation.*;
import org.w3c.dom.Document;

@RestController
@RequestMapping("/api/xml")
public class XmlProcessingController {

    private final SecureXmlConfiguration xmlConfig;

    public XmlProcessingController(SecureXmlConfiguration xmlConfig) {
        this.xmlConfig = xmlConfig;
    }

    @PostMapping("/process")
    public ResponseEntity<String> processXml(@RequestBody String xmlPayload) {
        try {
            // Parse XML with security controls
            Document doc = xmlConfig.parseXmlSecurely(xmlPayload);

            // Process document safely
            String result = processDocument(doc);
            return ResponseEntity.ok(result);

        } catch (SAXException e) {
            // Log potential attack attempt
            log.warn("Blocked malicious XML: {}", e.getMessage());
            return ResponseEntity.badRequest().body("Invalid XML: External entities not allowed");
        } catch (Exception e) {
            log.error("XML processing error", e);
            return ResponseEntity.status(500).body("XML processing failed");
        }
    }

    private String processDocument(Document doc) {
        // Your business logic here
        return doc.getDocumentElement().getNodeName();
    }
}

using System.Xml;
using Microsoft.AspNetCore.Mvc;
using System.Text;

namespace SecureXmlApi.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class XmlProcessingController : ControllerBase
    {
        private readonly ILogger<XmlProcessingController> _logger;

        public XmlProcessingController(ILogger<XmlProcessingController> logger)
        {
            _logger = logger;
        }

        /// <summary>
        /// Secure XML parsing using XmlReader with DTD protection
        /// </summary>
        [HttpPost("process")]
        public IActionResult ProcessXml([FromBody] string xmlContent)
        {
            try
            {
                var xmlDocument = ParseXmlSecurely(xmlContent);

                // Process the XML document
                var rootElement = xmlDocument.DocumentElement?.Name;
                return Ok(new { RootElement = rootElement, Status = "Success" });
            }
            catch (XmlException ex)
            {
                _logger.LogWarning("Blocked malicious XML: {Message}", ex.Message);
                return BadRequest(new { Error = "Invalid XML format", Details = "DTD processing is not allowed" });
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "XML processing error");
                return StatusCode(500, new { Error = "XML processing failed" });
            }
        }

        /// <summary>
        /// Secure XML parsing method with comprehensive protections
        /// </summary>
        private XmlDocument ParseXmlSecurely(string xmlContent)
        {
            // Create secure XmlReaderSettings
            var settings = new XmlReaderSettings
            {
                // CRITICAL: Prohibit DTD processing completely
                DtdProcessing = DtdProcessing.Prohibit,

                // Limit entity expansion to prevent billion laughs
                MaxCharactersFromEntities = 1024, // 1KB limit

                // Disable external resources
                XmlResolver = null,

                // Validation settings
                ValidationType = ValidationType.None,

                // Performance limits
                MaxCharactersInDocument = 10485760, // 10MB max document size

                // Additional security settings
                IgnoreComments = true,
                IgnoreProcessingInstructions = true,
                IgnoreWhitespace = true,

                // Prevent DoS via deeply nested elements
                Async = false
            };

            using var stringReader = new StringReader(xmlContent);
            using var xmlReader = XmlReader.Create(stringReader, settings);

            var doc = new XmlDocument()
            {
                // Disable XmlResolver to prevent XXE
                XmlResolver = null
            };

            doc.Load(xmlReader);
            return doc;
        }

        /// <summary>
        /// Alternative: Using XDocument (LINQ to XML) with secure settings
        /// </summary>
        private XDocument ParseWithXDocument(string xmlContent)
        {
            var settings = new XmlReaderSettings
            {
                DtdProcessing = DtdProcessing.Prohibit,
                MaxCharactersFromEntities = 1024,
                XmlResolver = null
            };

            using var stringReader = new StringReader(xmlContent);
            using var xmlReader = XmlReader.Create(stringReader, settings);

            return XDocument.Load(xmlReader, LoadOptions.None);
        }
    }

    /// <summary>
    /// Configuration for dependency injection
    /// </summary>
    public static class XmlSecurityConfiguration
    {
        public static void ConfigureXmlSecurity(this IServiceCollection services)
        {
            // Register secure XML settings as singleton
            services.AddSingleton<XmlReaderSettings>(provider =>
            {
                return new XmlReaderSettings
                {
                    DtdProcessing = DtdProcessing.Prohibit,
                    MaxCharactersFromEntities = 1024,
                    XmlResolver = null,
                    ValidationType = ValidationType.None,
                    MaxCharactersInDocument = 10485760
                };
            });
        }
    }
}

import org.springframework.stereotype.Service;
import org.springframework.web.filter.OncePerRequestFilter;
import io.github.bucket4j.Bandwidth;
import io.github.bucket4j.Bucket;
import io.github.bucket4j.Refill;
import javax.servlet.FilterChain;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import java.time.Duration;
import java.util.regex.Pattern;

/**
 * Pre-parsing XML validation service
 */
@Service
public class XmlValidationService {

    private static final int MAX_XML_SIZE_BYTES = 1_048_576; // 1MB
    private static final int MAX_NESTING_DEPTH = 50;
    private static final int MAX_ENTITY_DECLARATIONS = 0; // Reject any entity declarations
    private static final Pattern ENTITY_PATTERN = Pattern.compile("<!ENTITY\\s+", Pattern.CASE_INSENSITIVE);
    private static final Pattern DOCTYPE_PATTERN = Pattern.compile("<!DOCTYPE\\s+", Pattern.CASE_INSENSITIVE);

    /**
     * Validates XML before parsing to prevent DoS attacks
     */
    public ValidationResult validateXmlInput(String xmlContent) {

        // 1. Size check
        if (xmlContent.length() > MAX_XML_SIZE_BYTES) {
            return ValidationResult.reject("XML exceeds maximum size of 1MB");
        }

        // 2. Check for DOCTYPE declarations (indicator of DTD usage)
        if (DOCTYPE_PATTERN.matcher(xmlContent).find()) {
            return ValidationResult.reject("DOCTYPE declarations are not allowed");
        }

        // 3. Check for entity declarations (red flag for XML bombs)
        int entityCount = countMatches(ENTITY_PATTERN, xmlContent);
        if (entityCount > MAX_ENTITY_DECLARATIONS) {
            return ValidationResult.reject(
                String.format("XML contains %d entity declarations (max: %d)", 
                    entityCount, MAX_ENTITY_DECLARATIONS)
            );
        }

        // 4. Check nesting depth (prevent stack overflow)
        int nestingDepth = calculateNestingDepth(xmlContent);
        if (nestingDepth > MAX_NESTING_DEPTH) {
            return ValidationResult.reject(
                String.format("XML nesting depth %d exceeds maximum %d", 
                    nestingDepth, MAX_NESTING_DEPTH)
            );
        }

        // 5. Check for suspicious patterns (exponential entity references)
        if (xmlContent.contains("&lol") || xmlContent.contains("&bomb")) {
            return ValidationResult.reject("Suspicious entity references detected");
        }

        return ValidationResult.accept();
    }

    private int countMatches(Pattern pattern, String text) {
        int count = 0;
        var matcher = pattern.matcher(text);
        while (matcher.find()) count++;
        return count;
    }

    private int calculateNestingDepth(String xml) {
        int depth = 0;
        int maxDepth = 0;
        boolean inTag = false;

        for (int i = 0; i < xml.length(); i++) {
            char c = xml.charAt(i);
            if (c == '<') {
                inTag = true;
                if (i + 1 < xml.length() && xml.charAt(i + 1) != '/') {
                    depth++;
                    maxDepth = Math.max(maxDepth, depth);
                }
            } else if (c == '>' && inTag) {
                inTag = false;
                if (i > 0 && xml.charAt(i - 1) == '/') {
                    depth--;
                }
            } else if (c == '/' && inTag && i + 1 < xml.length() && xml.charAt(i + 1) == '>') {
                depth--;
            }
        }
        return maxDepth;
    }

    public static class ValidationResult {
        private final boolean valid;
        private final String errorMessage;

        private ValidationResult(boolean valid, String errorMessage) {
            this.valid = valid;
            this.errorMessage = errorMessage;
        }

        public static ValidationResult accept() {
            return new ValidationResult(true, null);
        }

        public static ValidationResult reject(String message) {
            return new ValidationResult(false, message);
        }

        public boolean isValid() { return valid; }
        public String getErrorMessage() { return errorMessage; }
    }
}

/**
 * Rate limiting filter using token bucket algorithm
 */
@Component
public class XmlRateLimitFilter extends OncePerRequestFilter {

    private final Map<String, Bucket> buckets = new ConcurrentHashMap<>();

    @Override
    protected void doFilterInternal(HttpServletRequest request, 
                                    HttpServletResponse response,
                                    FilterChain filterChain) throws ServletException, IOException {

        // Only apply to XML endpoints
        if (!request.getRequestURI().contains("/xml")) {
            filterChain.doFilter(request, response);
            return;
        }

        String clientId = getClientIdentifier(request);
        Bucket bucket = getBucket(clientId);

        if (bucket.tryConsume(1)) {
            filterChain.doFilter(request, response);
        } else {
            response.setStatus(429); // Too Many Requests
            response.setContentType("application/json");
            response.getWriter().write(
                "{\"error\":\"Rate limit exceeded\",\"retry_after\":60}"
            );
        }
    }

    private Bucket getBucket(String clientId) {
        return buckets.computeIfAbsent(clientId, k -> createBucket());
    }

    private Bucket createBucket() {
        // Allow 10 requests per minute per client
        Bandwidth limit = Bandwidth.classic(
            10, 
            Refill.intervally(10, Duration.ofMinutes(1))
        );
        return Bucket.builder().addLimit(limit).build();
    }

    private String getClientIdentifier(HttpServletRequest request) {
        // Combine IP and API key for rate limiting
        String apiKey = request.getHeader("X-API-Key");
        String ip = request.getRemoteAddr();
        return apiKey != null ? apiKey : ip;
    }
}
